/**
 * mesh-supervisor — the SINGLE consolidated mesh service front.
 *
 * One Cloud Run service / one GPU slot serving ALL models on demand. Fronts the
 * Cloud Run PORT and manages a single child = the proven single-model
 * openai-server+fat-station arm (docker-entrypoint.sh openai-server) running on
 * an internal port with one model's env. On a request for a different model it
 * restarts the child with that model's env (knot + tokenizer + template), waits
 * healthy, then proxies. Concurrent same-model requests proxy straight through —
 * the child's openai-server pipeline mutex serializes them (no cross-talk).
 *
 * Why: ~10 per-model gnosis-openai-* services fight over a 3-GPU quota →
 * cold-start 503s + handoff deadlocks. One service that swaps the model on the
 * single slot makes the unavoidable 1-GPU cost a single predictable load instead
 * of chaotic contention.
 *
 * Switches are serialized by a mutex so a model-swap never races a proxy.
 */

import fs from 'node:fs';
import http from 'node:http';
import https from 'node:https';
import net from 'node:net';
import { spawn, type ChildProcess } from 'node:child_process';
import {
  MESH_MODELS,
  resolveMeshModel,
  resolveMeshServingModel,
  defaultMeshModel,
  meshOpenAiModelIds,
  type MeshModelConfig,
} from '../mesh-model-registry';
import {
  buildMeshFederationManifest,
  parseMeshFederationPeers,
  resolveFederatedPeerForModel,
} from '../mesh-federation';

const PORT = Number(process.env['PORT'] ?? 8080);
const CHILD_PORT = Number(process.env['MESH_CHILD_PORT'] ?? 8090);
const CHILD_URL = `http://127.0.0.1:${CHILD_PORT}`;
const FAT_STATION_PORT = Number(process.env['MESH_FAT_STATION_PORT'] ?? 8000);
const FAT_STATION_URL = `http://127.0.0.1:${FAT_STATION_PORT}`;
const ENTRYPOINT = process.env['MESH_ENTRYPOINT'] ?? '/usr/local/bin/docker-entrypoint.sh';
const BENCH_DECODE_NEXT_BIN =
  process.env['MESH_BENCH_DECODE_NEXT_BIN'] ?? '/usr/local/bin/bench-decode-next';
const MESH_ID = process.env['MESH_ID'] ?? 'gnosis-openai-mesh';
const MESH_PUBLIC_URL = process.env['MESH_PUBLIC_URL'];
const FEDERATION_PEERS = parseMeshFederationPeers(process.env['MESH_FEDERATION_PEERS']);
// Model load can be slow (range-fetch a ~4.9GB knot + GPU load). Generous.
const CHILD_READY_TIMEOUT_MS = Number(process.env['MESH_CHILD_READY_TIMEOUT_MS'] ?? 600_000);
const CHILD_HEALTH_POLL_MS = 1500;
const PROFILE_TIMEOUT_MS = Number(process.env['MESH_PROFILE_TIMEOUT_MS'] ?? 180_000);
const CHILD_RESPONSE_TIMEOUT_MS = Number(process.env['MESH_CHILD_RESPONSE_TIMEOUT_MS'] ?? 120_000);
const CODESTRAL_FASTLANE = process.env['MESH_CODESTRAL_FASTLANE'] === '1';

function log(msg: string): void {
  console.error(`[mesh-supervisor] ${msg}`);
}

function rewriteOpenAiModelBody(bodyBuf: Buffer, model: string): Buffer {
  try {
    const parsed = JSON.parse(bodyBuf.toString('utf8')) as unknown;
    if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) return bodyBuf;
    return Buffer.from(JSON.stringify({ ...(parsed as Record<string, unknown>), model }), 'utf8');
  } catch {
    return bodyBuf;
  }
}

// ─────────────────────────── switch mutex ───────────────────────────
let _mutex: Promise<unknown> = Promise.resolve();
function withMutex<T>(fn: () => Promise<T>): Promise<T> {
  const run = _mutex.then(fn, fn);
  _mutex = run.then(
    () => undefined,
    () => undefined,
  );
  return run;
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

// ─────────────────────────── child lifecycle ───────────────────────────
let currentId: string | null = null;
let child: ChildProcess | null = null;
let activeModelRequests = 0;
let _childProxyMutex: Promise<unknown> = Promise.resolve();

const MODEL_SCOPED_ENV_KEYS = [
  'FAT_STATION_LAYERS',
  'MESH_STATION_URLS',
  'MESH_LAYER_RANGES',
  'MESH_HIDDEN_DIM',
  'MESH_VOCAB_SIZE',
  'MESH_LOCAL_STATION',
  'MESH_CHUNK_SIZE',
  'MESH_LOCAL_STATION_MAX_BATCH',
  'MOONSHINE_CONTINUOUS_BATCH',
  'MOONSHINE_DISABLE_NATIVE_GENERATE',
  'MESH_GPU_Q4K',
  'MESH_GPU_Q8K',
  'MESH_GPU_Q8K_F32',
  'MESH_GPU_Q8K_BUDGET_GB',
  'MESH_GPU_Q4K_BUDGET_GB',
  'KNOT_HTTP_TENSOR_CACHE_CAPACITY',
  'MOONSHINE_KNOT_BACKGROUND_LOCALIZE',
  'MOONSHINE_SOVEREIGN_SIEVE',
  'MOONSHINE_SOVEREIGN_SIEVE_AGREEMENT_K',
  'MOONSHINE_SIEVE_DEBUG',
  'FLUX_GPU_WEIGHT_DTYPE',
  'FLUX_GPU_F16_BUDGET_GB',
  'MOONSHINE_CHAT_TEMPLATE',
  'MOONSHINE_TOKENIZER_FAMILY',
  'TOKENIZER_JSON_URL',
  'TOKENIZER_GGUF_URL',
  'TOKENIZER_GGUF_PATH',
  'STOP_TOKENS',
] as const;

function modelOverridePrefix(modelId: string): string {
  return `MESH_MODEL_OVERRIDE_${modelId.toUpperCase().replace(/[^A-Z0-9]+/g, '_')}__`;
}

function applyModelScopedServiceOverrides(env: NodeJS.ProcessEnv, cfg: MeshModelConfig): void {
  const prefixes = new Set([
    modelOverridePrefix(cfg.id),
    modelOverridePrefix(cfg.modelName),
    ...cfg.aliases.map(modelOverridePrefix),
  ]);

  for (const prefix of prefixes) {
    for (const key of MODEL_SCOPED_ENV_KEYS) {
      const override = process.env[`${prefix}${key}`];
      if (override !== undefined) {
        env[key] = override;
      }
    }
  }
}

// Bound the pre-swap drain. A request whose client disconnected is NOT
// cancelled server-side (the generation runs to completion), so its lease can
// stay held for minutes — a cold model's first forward pays a per-weight
// Q8→f16 upload warmup. An unbounded wait let a single abandoned/slow request
// wedge EVERY subsequent request (all block behind the pending swap) until it
// finally finished — observed as 120s timeouts + minutes of Cloud Run 429s.
// After the timeout we proceed: `ensureModel` then calls `killChild()`, whose
// SIGTERM to the process group terminates the stuck in-flight work anyway, so
// force-proceeding is safe (the disconnected client is already gone).
const SWAP_DRAIN_TIMEOUT_MS = Number(
  process.env['MESH_SWAP_DRAIN_TIMEOUT_MS'] ?? 20_000,
);

async function waitForModelRequestsToDrain(nextId: string): Promise<void> {
  if (activeModelRequests === 0) return;
  log(
    `waiting for ${activeModelRequests} in-flight request(s) before swapping ${currentId} → ${nextId} (max ${SWAP_DRAIN_TIMEOUT_MS}ms)`,
  );
  const deadline = Date.now() + SWAP_DRAIN_TIMEOUT_MS;
  while (activeModelRequests > 0) {
    if (Date.now() >= deadline) {
      log(
        `drain timeout: ${activeModelRequests} request(s) still in flight after ${SWAP_DRAIN_TIMEOUT_MS}ms — proceeding with swap to ${nextId} (killChild will terminate them)`,
      );
      return;
    }
    await sleep(250);
  }
}

async function withModelRequestLease<T>(fn: () => Promise<T>): Promise<T> {
  activeModelRequests += 1;
  try {
    return await fn();
  } finally {
    activeModelRequests -= 1;
  }
}

function withChildProxyMutex<T>(fn: () => Promise<T>): Promise<T> {
  const run = _childProxyMutex.then(fn, fn);
  _childProxyMutex = run.then(
    () => undefined,
    () => undefined,
  );
  return run;
}

/**
 * Baked-knot preference: if the image carries this model's knot at
 * /models/<basename> (the Dockerfile.bake-knot layer), hand the child the
 * LOCAL path — the loader then mmaps demand-paged from the image layer
 * instead of HTTP-Range streaming into the tmpfs range cache. On Cloud Run
 * /tmp is tmpfs, so the range cache counts the knot against the memory
 * limit a SECOND time — for codestral-22b (23.6 GB Q8) that arithmetic is
 * what OOM-killed the child (exit 137, 2026-07-04).
 */
function resolveKnotSource(cfg: MeshModelConfig): string {
  const basename = cfg.knotUrl.split('/').pop();
  if (!basename) return cfg.knotUrl;
  const baked = `/models/${basename}`;
  try {
    if (fs.existsSync(baked) && fs.statSync(baked).size > 0) {
      log(`baked knot found for model=${cfg.id}: ${baked} (skipping HTTP range)`);
      return baked;
    }
  } catch {
    // fall through to the remote URL
  }
  return cfg.knotUrl;
}

function childEnv(cfg: MeshModelConfig): NodeJS.ProcessEnv {
  // Mirror the per-model service env so the child arm behaves identically.
  const env: NodeJS.ProcessEnv = {
    ...process.env,
    PORT: String(CHILD_PORT),
    FAT_STATION_PORT: String(FAT_STATION_PORT),
    MODEL_NAME: cfg.modelName,
    MODEL_ALIASES: [cfg.modelName, cfg.id, ...cfg.aliases].join(','),
    KNOT_URL: resolveKnotSource(cfg),
    MOONSHINE_TOKENIZER_FAMILY: cfg.tokenizerFamily,
    MOONSHINE_CHAT_TEMPLATE: cfg.chatTemplate,
    MOONSHINE_SKIP_ADMISSION_FORWARD: '1',
    HOME: process.env['HOME'] ?? '/tmp',
    KNOT_RANGE_CACHE_DIR: process.env['KNOT_RANGE_CACHE_DIR'] ?? '/tmp/knot-range-cache',
    // GPU/decode tunables: defaults here, but a SERVICE env var wins so we can
    // tune residency/budgets via `gcloud run update --update-env-vars` with NO
    // image rebuild. MIN_TOKENS=1 engages the GPU on tokens=1 decode (else CPU
    // fallback → ~1 tok/s).
    FLUX_GPU_MIN_TOKENS: process.env['FLUX_GPU_MIN_TOKENS'] ?? '1',
    FLUX_GPU_TF32: process.env['FLUX_GPU_TF32'] ?? '1',
    THOTH_LIQUID_MEMORY: process.env['THOTH_LIQUID_MEMORY'] ?? '0',
    MOONSHINE_PREFILL_WINDOWS: process.env['MOONSHINE_PREFILL_WINDOWS'] ?? '0',
  };
  // The consolidated service template can carry tuning from a prior model while
  // the supervisor swaps children in-process. Do not let model-scoped knobs bleed
  // into unrelated children; the registry is the source of truth here.
  for (const key of MODEL_SCOPED_ENV_KEYS) {
    delete env[key];
  }
  for (const [key, value] of Object.entries(cfg.env ?? {})) {
    env[key] = value;
  }
  // Per-model dtype/budget defaults from the registry. These are model-scoped:
  // a Codestral split-local budget must not accidentally apply to 7B models, and
  // a 7B f16 residency budget must not accidentally apply to Codestral.
  env['FLUX_GPU_WEIGHT_DTYPE'] = cfg.fluxGpuWeightDtype ?? 'f16';
  if (cfg.fluxGpuF16BudgetGb) {
    env['FLUX_GPU_F16_BUDGET_GB'] = String(cfg.fluxGpuF16BudgetGb);
  }
  if (cfg.tokenizerJsonUrl) env['TOKENIZER_JSON_URL'] = cfg.tokenizerJsonUrl;
  if (cfg.tokenizerGgufUrl) {
    // The entrypoint downloads TOKENIZER_GGUF_URL → TOKENIZER_GGUF_PATH (local).
    env['TOKENIZER_GGUF_URL'] = cfg.tokenizerGgufUrl;
    env['TOKENIZER_GGUF_PATH'] = `/tmp/${cfg.id}.tokenizer.gguf`;
  } else {
    delete env['TOKENIZER_GGUF_PATH'];
    delete env['TOKENIZER_GGUF_URL'];
  }
  if (cfg.stopTokens?.length) env['STOP_TOKENS'] = cfg.stopTokens.join(',');
  else delete env['STOP_TOKENS'];
  applyModelScopedServiceOverrides(env, cfg);
  return env;
}

async function childHealthy(): Promise<boolean> {
  try {
    const res = await fetch(`${CHILD_URL}/health`, {
      signal: AbortSignal.timeout(5000),
    });
    if (!res.ok) return false;
    const body = (await res.json()) as { status?: string };
    return body?.status === 'ok';
  } catch {
    return false;
  }
}

function killChild(): Promise<void> {
  return new Promise((resolve) => {
    const c = child;
    if (!c || c.exitCode !== null) {
      child = null;
      currentId = null;
      resolve();
      return;
    }
    log(`killing child group (model=${currentId}) to free the GPU for a swap`);
    const onExit = () => {
      child = null;
      currentId = null;
      resolve();
    };
    c.once('exit', onExit);
    // The arm backgrounds the fat-station then EXECs the openai-server, so the
    // fat-station is a sibling in the child's process GROUP. Signal the whole
    // group (negative pid) or the fat-station orphans and keeps the GPU. Falls
    // back to the single pid if the group signal fails.
    const signalGroup = (sig: NodeJS.Signals) => {
      try {
        if (c.pid) process.kill(-c.pid, sig);
      } catch {
        try {
          c.kill(sig);
        } catch {
          /* already gone */
        }
      }
    };
    signalGroup('SIGTERM');
    // Hard backstop: SIGKILL the group if it doesn't exit (must release the GPU).
    setTimeout(() => {
      if (c.exitCode === null) signalGroup('SIGKILL');
    }, 15_000);
  });
}

/** Wait until the child port is free (the prior child's openai-server may still
 *  hold it briefly after kill → EADDRINUSE on the next spawn). */
function waitPortFree(port: number, timeoutMs = 30_000): Promise<void> {
  return new Promise((resolve) => {
    const deadline = Date.now() + timeoutMs;
    const check = () => {
      const sock = net.connect({ port, host: '127.0.0.1' });
      sock.once('connect', () => {
        sock.destroy();
        if (Date.now() > deadline) {
          resolve(); // give up waiting; spawn anyway
          return;
        }
        setTimeout(check, 400); // still bound — keep waiting
      });
      sock.once('error', () => {
        sock.destroy();
        resolve(); // connection refused → port is free
      });
    };
    check();
  });
}

/** Nuclear backstop for the swap port race: SIGKILL whatever still holds a TCP port.
 *  killChild signals the child's process GROUP, but the openai-server is launched via
 *  the gnode/monster runner which can place the real server in a group the -pid signal
 *  misses, so the prior server can survive and keep $CHILD_PORT bound → the next child's
 *  bind EADDRINUSE-crash-loops (observed on mistral→codestral swaps). `fuser -k` (psmisc)
 *  is a definitive port-based kill. Best-effort: nonzero exit (nothing bound) or a missing
 *  binary both resolve — waitPortFree already ran, this only catches a stubborn holder. */
function forceFreePort(port: number): Promise<void> {
  return new Promise((resolve) => {
    const p = spawn('fuser', ['-k', '-KILL', `${port}/tcp`], { stdio: 'ignore' });
    p.on('exit', () => resolve());
    p.on('error', () => resolve());
  });
}

/**
 * Sweep the PRIOR models' knot artifacts out of /tmp before a swap. On Cloud
 * Run /tmp is tmpfs — every byte counts against the container memory limit.
 * The entrypoint's raced knot source fully downloads knots to /tmp AND the
 * loader keeps a range cache under /tmp/knot-range-cache, so swaps ACCUMULATE
 * gigabytes of dead tmpfs until any next child OOMs (observed 2026-07-04:
 * qwen2.5-7b and codestral-22b children exit 137 seconds after "ready", and
 * decode throughput on the surviving lane degraded ~6x from page-cache
 * thrash). Keep only artifacts whose basename matches the INCOMING model's
 * knot, so its own prior download/cache still warms the load.
 */
function sweepStaleKnotTmp(cfg: MeshModelConfig): void {
  const keep = cfg.knotUrl.split('/').pop() ?? '';
  const rm = (p: string) => {
    try {
      fs.rmSync(p, { recursive: true, force: true });
      log(`tmp sweep: removed ${p}`);
    } catch {
      /* best-effort */
    }
  };
  try {
    for (const name of fs.readdirSync('/tmp')) {
      if (!name.includes('.knot')) continue;
      if (keep && name.startsWith(keep)) continue;
      rm(`/tmp/${name}`);
    }
  } catch {
    /* /tmp unreadable — nothing to sweep */
  }
  const cacheDir = process.env['KNOT_RANGE_CACHE_DIR'] ?? '/tmp/knot-range-cache';
  try {
    for (const name of fs.readdirSync(cacheDir)) {
      if (keep && name.startsWith(keep)) continue;
      rm(`${cacheDir}/${name}`);
    }
  } catch {
    /* cache dir absent */
  }
}

async function spawnChild(cfg: MeshModelConfig): Promise<void> {
  sweepStaleKnotTmp(cfg);
  // The prior child's openai-server (CHILD_PORT) AND its backgrounded fat-station
  // (FAT_STATION_PORT) can BOTH linger for a moment after the group kill; spawning
  // before EITHER releases → EADDRINUSE crash (observed live: a swap to mamba-2.8b
  // crash-looped on `bind 0.0.0.0:8000` because only CHILD_PORT was waited on, so
  // the fat-station port was still held → the whole swap 503'd). Wait for both.
  // 90s (was 30s): a 7.3G-knot child (codestral) tears down slowly, so the prior
  // child can hold the ports well past 30s. The child openai-server ALSO retries the
  // listen on EADDRINUSE (authoritative in-process guard), so this is belt-and-suspenders.
  await Promise.all([waitPortFree(CHILD_PORT, 90_000), waitPortFree(FAT_STATION_PORT, 90_000)]);
  // Definitive: force-kill any stubborn holder the polite wait couldn't outlast, then
  // give the OS a beat to reclaim the socket before the new child binds.
  await forceFreePort(CHILD_PORT);
  await forceFreePort(FAT_STATION_PORT);
  await sleep(500);
  log(`spawning child for model=${cfg.id} (knot=${cfg.knotUrl})`);
  const c = spawn(ENTRYPOINT, ['openai-server'], {
    env: childEnv(cfg),
    stdio: ['ignore', 'inherit', 'inherit'],
    // Own process group so killChild() can signal the whole group (openai-server
    // + the backgrounded fat-station) and actually free the GPU on a swap.
    detached: true,
  });
  child = c;
  currentId = cfg.id;
  c.once('exit', (code, sig) => {
    log(`child (model=${cfg.id}) exited code=${code} sig=${sig}`);
    if (child === c) {
      child = null;
      currentId = null;
    }
  });
  // Poll the child /health until ready or timeout.
  const deadline = Date.now() + CHILD_READY_TIMEOUT_MS;
  while (Date.now() < deadline) {
    if (c.exitCode !== null) throw new Error(`child for ${cfg.id} exited during startup`);
    if (await childHealthy()) {
      log(`child ready: model=${cfg.id}`);
      return;
    }
    await sleep(CHILD_HEALTH_POLL_MS);
  }
  throw new Error(`child for ${cfg.id} did not become healthy within ${CHILD_READY_TIMEOUT_MS}ms`);
}

/** Ensure the child is serving `cfg`; restart it if a different model is loaded. */
async function ensureModel(cfg: MeshModelConfig): Promise<void> {
  if (currentId === cfg.id && child && child.exitCode === null && (await childHealthy())) {
    return; // already serving this model
  }
  if (currentId !== null && currentId !== cfg.id) {
    await waitForModelRequestsToDrain(cfg.id);
  }
  if (child) await killChild();
  await spawnChild(cfg);
}

// ─────────────────────────── proxy ───────────────────────────
// Hold-through-reload: a model swap kills+respawns the child (ensureModel →
// killChild/spawnChild), so the child can be momentarily unreachable
// (ECONNREFUSED while not-yet-listening) right when a request arrives. Rather
// than 502 immediately, HOLD the request and retry the CONNECT with a short
// backoff until the child is up — but ONLY while (a) no bytes have been streamed
// to the client yet (a streamed response can't be replayed) and (b) the loaded
// model is still the one this request was routed to (never silently retry across
// a swap → that would serve the WRONG model). Pairs with the child's SSE
// ack-and-hold so the end-to-end experience is "accepted + held", not a 500.
const PROXY_CONNECT_RETRIES = Number(process.env['MESH_PROXY_CONNECT_RETRIES'] ?? 8);
const PROXY_CONNECT_BACKOFF_MS = Number(
  process.env['MESH_PROXY_CONNECT_BACKOFF_MS'] ?? 500,
);
const TRANSIENT_PROXY_ERR = /ECONNREFUSED|ECONNRESET|EPIPE|socket hang up|ETIMEDOUT|EADDRNOTAVAIL/;

function proxyRequestHeaders(
  req: http.IncomingMessage,
  bodyBuf: Buffer,
  host: string,
): http.OutgoingHttpHeaders {
  const headers: http.OutgoingHttpHeaders = { ...req.headers, host };
  delete headers['transfer-encoding'];
  headers['content-length'] = String(bodyBuf.length);
  return headers;
}

async function proxyToChild(
  req: http.IncomingMessage,
  res: http.ServerResponse,
  bodyBuf: Buffer,
): Promise<void> {
  const targetId = currentId; // the model this proxy is bound to
  for (let attempt = 1; ; attempt++) {
    const outcome = await new Promise<'done' | 'retry'>((resolve) => {
      let settled = false;
      let upstreamComplete = false;
      let clientAborted = false;
      let deadlineTimer: NodeJS.Timeout | null = null;
      const settle = (outcome: 'done' | 'retry') => {
        if (settled) return;
        settled = true;
        if (deadlineTimer) {
          clearTimeout(deadlineTimer);
          deadlineTimer = null;
        }
        req.off('aborted', onClientGone);
        res.off('close', onClientGone);
        resolve(outcome);
      };
      const finish = () => settle('done');
      const killTargetChild = (reason: string) => {
        if (currentId === targetId) {
          log(`${reason}; killing child to unblock swaps`);
          void killChild().catch((error) => {
            log(`child kill failed after proxy abort: ${String(error)}`);
          });
        }
      };
      const onClientGone = () => {
        if (upstreamComplete || settled) {
          finish();
          return;
        }
        clientAborted = true;
        proxyReq.destroy(new Error('client closed before child response completed'));
        killTargetChild(`client closed while model=${targetId} was generating`);
        finish();
      };
      const proxyReq = http.request(
        `${CHILD_URL}${req.url}`,
        {
          method: req.method,
          headers: proxyRequestHeaders(req, bodyBuf, `127.0.0.1:${CHILD_PORT}`),
        },
        (proxyRes) => {
          res.writeHead(proxyRes.statusCode ?? 502, proxyRes.headers);
          proxyRes.pipe(res); // stream SSE through unbuffered
          proxyRes.once('end', () => {
            upstreamComplete = true;
            finish();
          });
          proxyRes.once('error', finish);
        },
      );
      if (CHILD_RESPONSE_TIMEOUT_MS > 0) {
        deadlineTimer = setTimeout(() => {
          if (settled || upstreamComplete) return;
          const detail = `child response exceeded ${CHILD_RESPONSE_TIMEOUT_MS}ms`;
          proxyReq.destroy(new Error(detail));
          if (!res.headersSent) {
            res.writeHead(504, { 'Content-Type': 'application/json' });
            res.end(
              JSON.stringify({
                error: 'mesh child response timeout',
                model: targetId,
                timeoutMs: CHILD_RESPONSE_TIMEOUT_MS,
              }),
            );
          } else {
            res.end();
          }
          killTargetChild(`${detail} for model=${targetId}`);
          finish();
        }, CHILD_RESPONSE_TIMEOUT_MS);
        deadlineTimer.unref();
      }
      req.once('aborted', onClientGone);
      res.once('close', onClientGone);
      proxyReq.on('error', (e) => {
        if (settled) {
          return;
        }
        if (clientAborted) {
          finish();
          return;
        }
        if (res.headersSent) {
          // Mid-stream failure: cannot replay, just close the truncated response.
          res.end();
          finish();
          return;
        }
        const transient = TRANSIENT_PROXY_ERR.test(String(e));
        if (transient && attempt < PROXY_CONNECT_RETRIES && currentId === targetId) {
          settle('retry'); // child (re)starting for the same model — hold + retry
          return;
        }
        res.writeHead(502, { 'Content-Type': 'application/json' });
        res.end(
          JSON.stringify({ error: 'mesh proxy error', detail: String(e), attempts: attempt }),
        );
        finish();
      });
      if (bodyBuf.length) proxyReq.write(bodyBuf);
      proxyReq.end();
    });
    if (outcome === 'done') return;
    log(`child not ready (model=${targetId}), hold+retry ${attempt}/${PROXY_CONNECT_RETRIES} in ${PROXY_CONNECT_BACKOFF_MS}ms`);
    await sleep(PROXY_CONNECT_BACKOFF_MS);
  }
}

// Stream a request through to a federation peer (its own Cloud Run URL). Mirrors
// proxyToChild but targets an arbitrary http(s) base. Auth/Authorization headers
// pass through; peer-to-peer IAM is a deploy concern (internal allow / minted id).
function proxyToPeer(
  req: http.IncomingMessage,
  res: http.ServerResponse,
  bodyBuf: Buffer,
  baseUrl: string,
): void {
  let target: URL;
  try {
    target = new URL(req.url ?? '/', baseUrl);
  } catch (e) {
    if (!res.headersSent) {
      res.writeHead(502, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'mesh peer url invalid', detail: String(e) }));
    } else {
      res.end();
    }
    return;
  }
  const opts = {
    method: req.method,
    headers: proxyRequestHeaders(req, bodyBuf, target.host),
  };
  const onRes = (proxyRes: http.IncomingMessage) => {
    res.writeHead(proxyRes.statusCode ?? 502, proxyRes.headers);
    proxyRes.pipe(res); // stream SSE through unbuffered
  };
  const proxyReq =
    target.protocol === 'https:'
      ? https.request(target, opts, onRes)
      : http.request(target, opts, onRes);
  proxyReq.on('error', (e) => {
    if (!res.headersSent) {
      res.writeHead(502, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ error: 'mesh peer proxy error', detail: String(e) }));
    } else {
      res.end();
    }
  });
  if (bodyBuf.length) proxyReq.write(bodyBuf);
  proxyReq.end();
}

function readBody(req: http.IncomingMessage): Promise<Buffer> {
  return new Promise((resolve) => {
    const chunks: Buffer[] = [];
    req.on('data', (c: Buffer) => chunks.push(c));
    req.on('end', () => resolve(Buffer.concat(chunks)));
  });
}

function parseBoundedInt(
  params: URLSearchParams,
  name: string,
  fallback: number,
  min: number,
  max: number,
): number {
  const raw = params.get(name);
  if (raw === null || raw.trim() === '') return fallback;
  const value = Number(raw);
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new Error(`${name} must be an integer in [${min}, ${max}]`);
  }
  return value;
}

function parseOptionalMode(params: URLSearchParams, name: string): string | null {
  const raw = params.get(name);
  if (raw === null || raw.trim() === '') return null;
  const value = raw.trim();
  if (!/^[A-Za-z0-9._:-]{1,128}$/.test(value)) {
    throw new Error(`${name} contains unsupported characters`);
  }
  return value;
}

function authorizeProfile(req: http.IncomingMessage): boolean {
  const expected = process.env['MESH_PROFILE_TOKEN'];
  const actual = req.headers['x-mesh-profile-token'];
  return typeof expected === 'string' && expected.length > 0 && actual === expected;
}

function appendBounded(target: { value: string }, chunk: Buffer): void {
  const maxChars = 128_000;
  if (target.value.length >= maxChars) return;
  target.value += chunk.toString('utf8').slice(0, maxChars - target.value.length);
}

function runBenchDecodeNext(params: URLSearchParams): Promise<{
  args: string[];
  code: number | null;
  signal: NodeJS.Signals | null;
  stdout: string;
  stderr: string;
  durationMs: number;
}> {
  const warmup = parseBoundedInt(params, 'warmup', 2, 0, 32);
  const iterations = parseBoundedInt(params, 'iterations', 24, 1, 256);
  const token = parseBoundedInt(params, 'token', 8, 0, 1_000_000);
  const position = parseBoundedInt(params, 'position', 0, 0, 1_000_000);
  const label = params.get('label')?.trim() || 'mesh-decode-next';
  if (!/^[A-Za-z0-9._:-]{1,128}$/.test(label)) {
    throw new Error('label contains unsupported characters');
  }
  const args = [
    '--url',
    FAT_STATION_URL,
    '--label',
    label,
    '--warmup',
    String(warmup),
    '--iterations',
    String(iterations),
    '--token',
    String(token),
    '--position',
    String(position),
    '--json-summary',
  ];
  const ffnMode = parseOptionalMode(params, 'ffn-mode');
  if (ffnMode) args.push('--ffn-mode', ffnMode);

  return new Promise((resolve, reject) => {
    const stdout = { value: '' };
    const stderr = { value: '' };
    const started = Date.now();
    const childProc = spawn(BENCH_DECODE_NEXT_BIN, args, {
      stdio: ['ignore', 'pipe', 'pipe'],
    });
    const timeout = setTimeout(() => {
      childProc.kill('SIGTERM');
    }, PROFILE_TIMEOUT_MS);
    childProc.stdout?.on('data', (chunk: Buffer) => appendBounded(stdout, chunk));
    childProc.stderr?.on('data', (chunk: Buffer) => appendBounded(stderr, chunk));
    childProc.once('error', (error) => {
      clearTimeout(timeout);
      reject(error);
    });
    childProc.once('exit', (code, signal) => {
      clearTimeout(timeout);
      resolve({
        args,
        code,
        signal,
        stdout: stdout.value,
        stderr: stderr.value,
        durationMs: Date.now() - started,
      });
    });
  });
}

const server = http.createServer((req, res) => {
  void (async () => {
    let clientClosed = false;
    req.once('aborted', () => {
      clientClosed = true;
    });

    // Supervisor-level health (always available, no GPU): reports the loaded model.
    if (req.url === '/health' && req.method === 'GET') {
      const ok = currentId !== null && (await childHealthy());
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(
        JSON.stringify({
          status: 'ok',
          mesh: true,
          loadedModel: currentId,
          childReady: ok,
          peerCount: FEDERATION_PEERS.length,
        }),
      );
      return;
    }

    const parsedUrl = new URL(req.url ?? '/', 'http://mesh.local');
    if (parsedUrl.pathname === '/__mesh/manifest' && req.method === 'GET') {
      const ok = currentId !== null && (await childHealthy());
      const manifestInput = {
        meshId: MESH_ID,
        loadedModel: currentId,
        childReady: ok,
        models: MESH_MODELS,
        peers: FEDERATION_PEERS,
      };
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(
        JSON.stringify(
          buildMeshFederationManifest({
            ...manifestInput,
            ...(MESH_PUBLIC_URL ? { publicUrl: MESH_PUBLIC_URL } : {}),
          }),
        ),
      );
      return;
    }

    if (parsedUrl.pathname === '/v1/models' && req.method === 'GET') {
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(
        JSON.stringify({
          object: 'list',
          data: meshOpenAiModelIds().map((id) => ({
            id,
            object: 'model',
            owned_by: 'gnosis',
            created: 0,
          })),
        }),
      );
      return;
    }

    if (parsedUrl.pathname === '/__mesh/bench-decode-next') {
      if (req.method !== 'POST') {
        res.writeHead(405, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'method not allowed' }));
        return;
      }
      if (process.env['MESH_PROFILE_DECODE_NEXT'] !== '1') {
        res.writeHead(404, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'profile route disabled' }));
        return;
      }
      if (!authorizeProfile(req)) {
        res.writeHead(403, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'profile token required' }));
        return;
      }
      const requested = parsedUrl.searchParams.get('model') ?? undefined;
      const cfg = resolveMeshModel(requested) ?? (requested ? null : defaultMeshModel());
      if (!cfg) {
        res.writeHead(400, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'unknown model', model: requested }));
        return;
      }
      try {
        const profile = await withMutex(async () => {
          await ensureModel(cfg);
          return await runBenchDecodeNext(parsedUrl.searchParams);
        });
        res.writeHead(profile.code === 0 ? 200 : 500, { 'Content-Type': 'application/json' });
        res.end(
          JSON.stringify({
            kind: 'mesh-decode-next-profile',
            model: cfg.id,
            command: [BENCH_DECODE_NEXT_BIN, ...profile.args],
            ...profile,
          }),
        );
      } catch (e) {
        res.writeHead(500, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'profile failed', detail: String(e) }));
      }
      return;
    }

    const bodyBuf = await readBody(req);

    // Chat completions: resolve model → ensure loaded → proxy.
    if (req.url === '/v1/chat/completions' && req.method === 'POST') {
      let requested: string | undefined;
      try {
        requested = (JSON.parse(bodyBuf.toString('utf8')) as { model?: string }).model;
      } catch {
        /* fall through to default model */
      }
      const resolution = requested
        ? resolveMeshServingModel(requested, { codestralFastLane: CODESTRAL_FASTLANE })
        : null;
      const cfg = resolution
        ? resolution.config
        : currentId
          ? resolveMeshModel(currentId)
          : defaultMeshModel();
      if (!cfg) {
        res.writeHead(400, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'unknown model', model: requested }));
        return;
      }
      const proxiedBodyBuf = resolution?.rewriteModel
        ? rewriteOpenAiModelBody(bodyBuf, resolution.rewriteModel)
        : bodyBuf;
      if (resolution?.routedFrom && resolution.reason) {
        log(
          `routing requested model=${requested} (${resolution.routedFrom}) via ${cfg.id} reason=${resolution.reason}`,
        );
      }
      // MESH ROUTING: if this node isn't already serving the model but a peer is,
      // forward to the peer instead of swapping our GPU. This is what stops the
      // single-GPU swap-thrash — different models live on different peers, each
      // scale-to-zero ($0 idle; cold-start on demand, never kept warm). No-op when
      // MESH_FEDERATION_PEERS is empty (peers=0) → behaviour identical to today.
      if (currentId !== cfg.id) {
        const peer = resolveFederatedPeerForModel(cfg.id, FEDERATION_PEERS);
        if (peer) {
          log(`routing model=${cfg.id} → peer ${peer.id} (${peer.baseUrl})`);
          proxyToPeer(req, res, proxiedBodyBuf, peer.baseUrl);
          return;
        }
      }
      let loadingForClient = true;
      const abortLoadForClosedClient = () => {
        if (!loadingForClient) return;
        if (currentId === cfg.id) {
          clientClosed = true;
          log(`client aborted while model=${cfg.id} was loading; killing child to unblock swaps`);
          void killChild().catch((error) => {
            log(`client-close load kill failed: ${String(error)}`);
          });
        }
      };
      req.once('aborted', abortLoadForClosedClient);
      try {
        // No peer serves it → load locally (the swap-lane for the long tail).
        // Serialize swaps: a model load never races a proxied request.
        await withMutex(() => ensureModel(cfg));
      } catch (e) {
        loadingForClient = false;
        res.writeHead(503, { 'Content-Type': 'application/json' });
        res.end(
          JSON.stringify({
            error: 'mesh model load failed',
            model: cfg.id,
            detail: String(e),
          }),
        );
        return;
      }
      loadingForClient = false;
      if (clientClosed || req.aborted) {
        if (currentId === cfg.id) {
          log(`client aborted while model=${cfg.id} was loading; killing child to unblock swaps`);
          void killChild().catch((error) => {
            log(`client-close load kill failed: ${String(error)}`);
          });
        }
        return;
      }
      await withModelRequestLease(() =>
        withChildProxyMutex(() => proxyToChild(req, res, proxiedBodyBuf)),
      );
      return;
    }

    // Everything else → proxy to the current child (boot the default if cold).
    if (currentId === null) {
      try {
        await withMutex(() => ensureModel(defaultMeshModel()));
      } catch (e) {
        res.writeHead(503, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'mesh boot failed', detail: String(e) }));
        return;
      }
    }
    await withModelRequestLease(() =>
      withChildProxyMutex(() => proxyToChild(req, res, bodyBuf)),
    );
  })();
});

server.listen(PORT, '0.0.0.0', () => {
  log(
    `listening on :${PORT} (child port ${CHILD_PORT}); models: ${MESH_IDS()}; peers=${FEDERATION_PEERS.length}`,
  );
});

function MESH_IDS(): string {
  // lazy import-free id list for the boot log
  try {
    return defaultMeshModel().id + ' (+registry)';
  } catch {
    return '?';
  }
}

process.on('SIGTERM', () => {
  void killChild().then(() => process.exit(0));
});
process.on('SIGINT', () => {
  void killChild().then(() => process.exit(0));
});
